CREATE TABLE `mysqldb`.`tablename` (`id_voice` BIGINT NOT NULL AUTO_INCREMENT, `time` VARCHAR(45) NOT NULL, `guild-id` VARCHAR(45) NOT NULL, `guild-name` LONGTEXT NOT NULL, `user-id` VARCHAR(45) NOT NULL, `user-name` LONGTEXT NOT NULL, `voicechannel-id` VARCHAR(45) NOT NULL, `voicechannel-name` LONGTEXT NOT NULL, `selfdeaf` TINYINT NOT NULL, `selfmute` TINYINT NOT NULL, `serverdeaf` TINYINT NOT NULL, `servermute` TINYINT NOT NULL, PRIMARY KEY (`id_voice`)) ROW_FORMAT=COMPRESSED;